      "path": "src/modules/tasks/routes.js",
      "content": "const express = require('express');
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

// Get all tasks for a project
router.get('/', async (req, res) => {
  const { projectId } = req.params;
  try {
    const tasks = await tasksService.getAllTasks(projectId);
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

// Get all done tasks for a project
router.get('?status=done', async (req, res) => {
  const { projectId } = req.params;
  try {
    const tasks = await tasksService.getAllDoneTasks(projectId);
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

// Create a new task for a project
router.post('/', async (req, res) => {
  const { title } = req.body;
  if (!title || typeof title !== 'string' || title.trim() === '') {
    return sendError(res, 400, 'INVALID_TITLE', 'Title must be a non-empty string');
  }
  try {
    const task = await tasksService.createTask(projectId, title);
    res.status(201).json({ task });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

// Update a task status
router.patch('/:taskId', async (req, res) => {
  const { taskId } = req.params;
  const { status } = req.body;
  if (!status || typeof status !== 'string' || ![ 'todo', 'done' ].includes(status)) {
    return sendError(res, 400, 'INVALID_STATUS', 'Invalid status');
  }
  try {
    const task = await tasksService.updateTaskStatus(taskId, status);
    if (!task) {
      return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
    }
    res.json({ task });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;
