      "content": "const { randomUUID } = require('../../lib/id');

let tasksStore = [];

const getAllTasks = (projectId) => {
  return Promise.resolve(tasksStore.filter(t => t.projectId === projectId));
};

const getAllDoneTasks = (projectId) => {
  return Promise.resolve(tasksStore.filter(t => t.projectId === projectId && t.status === 'done'));
};

const createTask = (projectId, title) => {
  const task = { id: randomUUID(), projectId, title, status: 'todo' };
  tasksStore.push(task);
  return Promise.resolve(task);
};

const updateTaskStatus = (taskId, status) => {
  const task = tasksStore.find(t => t.id === taskId);
  if (!task) {
    return Promise.resolve(null);
  }
  task.status = status;
  return Promise.resolve(task);
};

module.exports = { getAllTasks, getAllDoneTasks, createTask, updateTaskStatus };
